const SECRET_PATTERNS=[{pattern:/jdbc:[a-zA-Z]+:\/\/[^\s"']+/gi,type:"JDBC URL",severity:"CRITICAL"},{pattern:/(?:spring\.datasource\.password|db\.password|jdbc\.password)\s*[=:]\s*[^\s\n]+/gi,type:"DB Password Config",severity:"CRITICAL"},{pattern:/(?:password|passwd|pwd)\s*[=:]\s*["']?[^\s"'\n]{8,}["']?/gi,type:"Password Value",severity:"HIGH"},{pattern:/\bsk-[a-zA-Z0-9_-]{20,}\b/g,type:"OpenAI API Key",severity:"CRITICAL"},{pattern:/\bsk-proj-[a-zA-Z0-9_-]{20,}\b/g,type:"OpenAI Project Key",severity:"CRITICAL"},{pattern:/\bAKIA[A-Z0-9]{16,}\b/g,type:"AWS Access Key",severity:"CRITICAL"},{pattern:/\bghp_[a-zA-Z0-9]{36,}\b/g,type:"GitHub PAT",severity:"CRITICAL"},{pattern:/\bghs_[a-zA-Z0-9]{36,}\b/g,type:"GitHub App Token",severity:"CRITICAL"},{pattern:/\bglpat-[a-zA-Z0-9_-]{20,}\b/g,type:"GitLab PAT",severity:"CRITICAL"},{pattern:/\bnpm_[a-zA-Z0-9]{36,}\b/g,type:"NPM Token",severity:"CRITICAL"},{pattern:/\bBearer\s+[a-zA-Z0-9_.\-]{20,}\b/gi,type:"Bearer Token",severity:"HIGH"},{pattern:/\btoken\s*[=:]\s*["']?[a-zA-Z0-9_.\-]{20,}["']?/gi,type:"Token Parameter",severity:"HIGH"},{pattern:/\bauth\s*[=:]\s*["']?[a-zA-Z0-9_.\-]{20,}["']?/gi,type:"Auth Parameter",severity:"HIGH"},{pattern:/\bapi[_-]?key\s*[=:]\s*["']?[a-zA-Z0-9_.\-]{20,}["']?/gi,type:"API Key Parameter",severity:"HIGH"},{pattern:/\beyJ[a-zA-Z0-9_-]{10,}\.[a-zA-Z0-9_-]{10,}\.[a-zA-Z0-9_-]{10,}\b/g,type:"JWT Token",severity:"CRITICAL"},{pattern:/\bAWS_SECRET_ACCESS_KEY\s*[=:]\s*[^\s\n]{20,}/gi,type:"AWS Secret Key",severity:"CRITICAL"},{pattern:/\bOPENAI_API_KEY\s*[=:]\s*[^\s\n]{20,}/gi,type:"OpenAI Key Value",severity:"CRITICAL"},{pattern:/\bANTHROPIC_API_KEY\s*[=:]\s*[^\s\n]{20,}/gi,type:"Anthropic Key Value",severity:"CRITICAL"},{pattern:/\bGITHUB_TOKEN\s*[=:]\s*[^\s\n]{20,}/gi,type:"GitHub Token Value",severity:"CRITICAL"},{pattern:/\bDATABASE_URL\s*[=:]\s*[^\s\n]{20,}/gi,type:"Database URL Value",severity:"CRITICAL"},{pattern:/-----BEGIN (?:RSA |EC |DSA |OPENSSH )?PRIVATE KEY-----/g,type:"Private Key",severity:"CRITICAL"},{pattern:/(?:spring\.security|spring\.mail|spring\.redis)\.password\s*[=:]\s*[^\s\n]+/gi,type:"Spring Config Secret",severity:"HIGH"},{pattern:/(?:encrypt|decrypt)\.key\s*[=:]\s*[^\s\n]+/gi,type:"Encryption Key",severity:"CRITICAL"},{pattern:/(?:key|secret|token|password|credential|auth)\s*[=:]\s*["']?[a-zA-Z0-9+/]{40,}={0,2}["']?/gi,type:"Potential Base64 Secret",severity:"MEDIUM"},{pattern:/(?:password|secret|token|api_key|apikey)%3[Dd](?:%[0-9A-Fa-f]{2}|[a-zA-Z0-9._~!$&'()*+,;=:@/-]){8,}/gi,type:"URL-Encoded Secret",severity:"HIGH"}];function maskSecret(original){if(original.length>16){return original.substring(0,8)+"***MASKED***"+original.substring(original.length-4)}return original.substring(0,4)+"***MASKED***"}function checkBase64Encoded(text){const b64Pattern=/[A-Za-z0-9+/]{20,}={0,2}/g;let match;while((match=b64Pattern.exec(text))!==null){try{const decoded=Buffer.from(match[0],"base64").toString("utf-8");if(decoded.length>=10){for(const{pattern}of SECRET_PATTERNS){pattern.lastIndex=0;if(pattern.test(decoded)){return true}}}}catch{}}return false}function checkUrlEncoded(text){const matches=[];const urlPattern=/(?:password|secret|token|api_key|apikey|pwd|passwd)(?:%3[Dd]|=)(?:%[0-9A-Fa-f]{2}|[a-zA-Z0-9._~!$&'()*+,;:@/-]){8,}/gi;let match;while((match=urlPattern.exec(text))!==null){try{const decoded=decodeURIComponent(match[0]);for(const{pattern}of SECRET_PATTERNS){pattern.lastIndex=0;if(pattern.test(decoded)){matches.push({index:match.index,length:match[0].length,value:match[0]});break}}}catch{if(match[0].length>30){matches.push({index:match.index,length:match[0].length,value:match[0]})}}}return{found:matches.length>0,matches:matches}}function filterSecrets(toolResult){let maskedOutput=toolResult;let maskedCount=0;const maskedTypes=new Set;for(const{pattern,type}of SECRET_PATTERNS){pattern.lastIndex=0;const matches=[];let m;while((m=pattern.exec(maskedOutput))!==null){matches.push({index:m.index,length:m[0].length,value:m[0]})}for(let i=matches.length-1;i>=0;i--){const{index,length,value}=matches[i];maskedOutput=maskedOutput.substring(0,index)+maskSecret(value)+maskedOutput.substring(index+length);maskedCount++;maskedTypes.add(type)}}const urlEncodedResult=checkUrlEncoded(maskedOutput);if(urlEncodedResult.found){for(const match of urlEncodedResult.matches){maskedOutput=maskedOutput.substring(0,match.index)+maskSecret(match.value)+maskedOutput.substring(match.index+match.length);maskedCount++;maskedTypes.add("URL-Encoded Secret")}}if(checkBase64Encoded(toolResult)){const b64Pattern=/[A-Za-z0-9+/]{40,}={0,2}/g;const b64Matches=[];let b64Match;while((b64Match=b64Pattern.exec(maskedOutput))!==null){try{const decoded=Buffer.from(b64Match[0],"base64").toString("utf-8");for(const{pattern,type}of SECRET_PATTERNS){pattern.lastIndex=0;if(pattern.test(decoded)){b64Matches.push({index:b64Match.index,length:b64Match[0].length,value:b64Match[0],type:"Base64-Encoded "+type});break}}}catch{}}for(let i=b64Matches.length-1;i>=0;i--){const{index,length,value,type}=b64Matches[i];maskedOutput=maskedOutput.substring(0,index)+maskSecret(value)+maskedOutput.substring(index+length);maskedCount++;maskedTypes.add(type)}}return{maskedOutput:maskedOutput,maskedCount:maskedCount,maskedTypes:Array.from(maskedTypes)}}function logMasking(toolName,count,types){const fs=require("fs");const path=require("path");const logPath=path.join(process.cwd(),".claude","hooks","security-masking.log");const timestamp=(new Date).toISOString();const logEntry=`${timestamp} | SECRET_MASKED | tool=${toolName} | count=${count} | types=${types.join(",")}\n`;try{fs.appendFileSync(logPath,logEntry)}catch{}}if(require.main===module){let input="";process.stdin.setEncoding("utf8");process.stdin.on("data",chunk=>{input+=chunk});process.stdin.on("end",()=>{try{const event=JSON.parse(input);const toolResult=event.tool_result||"";const toolName=event.tool_name||"unknown";const resultText=typeof toolResult==="string"?toolResult:JSON.stringify(toolResult,null,2);if(!resultText||resultText.length<10){process.exit(0);return}const{maskedOutput,maskedCount,maskedTypes}=filterSecrets(resultText);if(maskedCount>0){process.stdout.write(maskedOutput);process.stderr.write(`\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`+`SECRET MASKED | ${maskedCount}건 | ${maskedTypes.join(", ")}\n`+`━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`);logMasking(toolName,maskedCount,maskedTypes)}process.exit(0)}catch(e){process.exit(0)}});setTimeout(()=>{process.exit(0)},5e3)}module.exports={filterSecrets:filterSecrets,maskSecret:maskSecret,checkBase64Encoded:checkBase64Encoded,checkUrlEncoded:checkUrlEncoded,SECRET_PATTERNS:SECRET_PATTERNS};